import bpy
for light in bpy.data.lights:
    if light.type in ['SUN', 'AREA', 'POINT']:
        light.energy *= 2.0
scene = bpy.context.scene
if scene.world and scene.world.use_nodes:
    bg_node = scene.world.node_tree.nodes.get('Background')
    if bg_node:
        bg_node.inputs[1].default_value = 1.0

import bpy
for light in bpy.data.lights:
    if light.type in ['SUN', 'AREA', 'POINT']:
        light.energy *= 0.5
scene = bpy.context.scene
if scene.world and scene.world.use_nodes:
    bg_node = scene.world.node_tree.nodes.get('Background')
    if bg_node:
        bg_node.inputs[1].default_value = 0.6
scene.render.use_high_quality_normals = True

import bpy
for material in bpy.data.materials:
    if material.use_nodes:
        bsdf = material.node_tree.nodes.get('Principled BSDF')
        if bsdf:
            if 'Glass' in material.name or 'glass' in material.name.lower():
                bsdf.inputs['Metallic'].default_value = 0.0
                bsdf.inputs['Roughness'].default_value = 0.0
                bsdf.inputs['IOR'].default_value = 1.45
            elif 'Vehicle' in material.name or 'vehicle' in material.name.lower():
                bsdf.inputs['Metallic'].default_value = 0.8
                bsdf.inputs['Roughness'].default_value = 0.3
            else:
                bsdf.inputs['Roughness'].default_value = 0.7

import bpy
default_grey = (0.8, 0.8, 0.8)
for obj in bpy.data.objects:
    if obj.type == 'MESH' and obj.data.materials:
        for mat in obj.data.materials:
            if mat.use_nodes:
                bsdf = mat.node_tree.nodes.get('Principled BSDF')
                if bsdf:
                    current = bsdf.inputs['Base Color'].default_value
                    if abs(current[0] - 0.8) < 0.05:
                        if 'Vehicle' in obj.name or 'Car' in obj.name:
                            bsdf.inputs['Base Color'].default_value = (0.1, 0.1, 0.15, 1.0)
                        elif 'Road' in obj.name or 'Asphalt' in obj.name:
                            bsdf.inputs['Base Color'].default_value = (0.2, 0.2, 0.22, 1.0)

import bpy
primitives = ['Cube', 'Sphere', 'Plane', 'Cylinder', 'Cone']
for obj in bpy.data.objects:
    if obj.type == 'MESH':
        if any(prim in obj.name for prim in primitives):
            bpy.data.objects.remove(obj, do_unlink=True)
print('Removed placeholder primitives')

import bpy
camera = bpy.context.scene.camera
if camera:
    camera.data.dof.use_dof = True
    camera.data.dof.aperture_fstop = 5.0
    camera.data.dof.focus_distance = 10.0
    for obj in bpy.data.objects:
        if 'BG' in obj.name or 'Background' in obj.name:
            obj.location.z -= 50.0

import bpy
scene = bpy.context.scene
for obj in bpy.data.objects:
    if obj.type == 'MESH' and 'Vehicle' in obj.name:
        if obj.data.shape_keys:
            for key_block in obj.data.shape_keys.key_blocks:
                if 'Damage' in key_block.name or 'Impact' in key_block.name:
                    key_block.keyframe_insert('value', frame=120)
                    key_block.value = 1.0
print('Applied deformation keyframes')

import bpy
for obj in bpy.data.objects:
    if obj.type == 'MESH' and ('Interior' in obj.name or 'Dashboard' in obj.name or 'Seat' in obj.name):
        obj.hide_render = False
        obj.hide_set(False)
        if obj.data.materials:
            for mat in obj.data.materials:
                if mat.use_nodes:
                    bsdf = mat.node_tree.nodes.get('Principled BSDF')
                    if bsdf:
                        bsdf.inputs['Base Color'].default_value = (0.3, 0.3, 0.35, 1.0)

import bpy
scene = bpy.context.scene
scene.cycles.use_adaptive_sampling = False
scene.cycles.samples = 256
scene.cycles.use_denoising = True
scene.cycles.denoiser = 'OPENIMAGEDENOISE'
for light in bpy.data.lights:
    if light.animation_data:
        light.animation_data_clear()
for world in bpy.data.worlds:
    if world.animation_data:
        world.animation_data_clear()
print('Configured for stable temporal render')

import bpy
for light in bpy.data.lights:
    if light.animation_data:
        for action in light.animation_data.nla_tracks:
            light.animation_data.nla_tracks.remove(action)
for world in bpy.data.worlds:
    if world.animation_data:
        world.animation_data_clear()
scene = bpy.context.scene
if scene.use_nodes:
    for node in scene.node_tree.nodes:
        if node.type == 'EXPOSURE':
            node.inputs['Exposure'].default_value = 0.5
print('Removed exposure animation')
